public class JsonSerializer {

    public String serialize(Object obj) throws Exception {
        if (obj == null) return "null";
        if (obj instanceof String) return "\"" + obj + "\"";
        if (obj instanceof Number || obj instanceof Boolean) return obj.toString();
        if (obj instanceof List) {
            return serializeList((List<?>) obj);
        }
        return serializeObject(obj);
    }

    private String serializeList(List<?> list) throws Exception {
        // TODO: Serialize as JSON array [item1, item2, ...]
        return "[]";
    }

    private String serializeObject(Object obj) throws Exception {
        // TODO: Use reflection to get all fields and serialize as JSON object
        // {"fieldName": value, ...}
        return "{}";
    }
}

public class Address {
    public String street;
    public String city;

    public Address(String street, String city) {
        this.street = street; this.city = city;
    }
}

public class Person {
    public int id;
    public String name;
    public boolean active;
    public List<String> skills;

    public Person(int id, String name, boolean active, List<String> skills) {
        this.id = id; this.name = name; this.active = active; this.skills = skills;
    }
}

public class Main {
    public static void main(String[] args) throws Exception {
        JsonSerializer serializer = new JsonSerializer();

        Person person = new Person(1, "Alice", true, Arrays.asList("Java", "Spring"));
        System.out.println(serializer.serialize(person));

        System.out.println(serializer.serialize("Hello World"));
        System.out.println(serializer.serialize(42));
        System.out.println(serializer.serialize(Arrays.asList(1, 2, 3)));
    }
}

