public class SimpleJsonParser {

    public Map<String, Object> parseObject(String json) {
        // TODO: Parse simple flat JSON object (no nesting) into a Map
        // Input: '{"name":"Alice","age":30,"active":true}'
        // Handles: string values (quoted), number values, boolean values
        Map<String, Object> result = new LinkedHashMap<>();
        // Strip curly braces
        json = json.trim();
        if (json.startsWith("{")) json = json.substring(1, json.length() - 1);

        // TODO: Split by comma (outside quotes), then split each pair by ':'
        // Parse value: if quoted -> String, if 'true'/'false' -> Boolean, else -> Integer
        return result;
    }

    public String getString(Map<String, Object> parsed, String key) {
        Object val = parsed.get(key);
        return val != null ? val.toString() : null;
    }

    public int getInt(Map<String, Object> parsed, String key, int defaultValue) {
        Object val = parsed.get(key);
        if (val instanceof Integer) return (Integer) val;
        if (val instanceof String) { try { return Integer.parseInt((String) val); } catch (Exception e) {} }
        return defaultValue;
    }

    public boolean getBoolean(Map<String, Object> parsed, String key) {
        Object val = parsed.get(key);
        return Boolean.TRUE.equals(val);
    }
}

public class Main {
    public static void main(String[] args) {
        SimpleJsonParser parser = new SimpleJsonParser();

        String json = "{\"name\":\"Alice\",\"age\":30,\"active\":true}";
        Map<String, Object> parsed = parser.parseObject(json);

        System.out.println("Name: " + parser.getString(parsed, "name"));
        System.out.println("Age: " + parser.getInt(parsed, "age", 0));
        System.out.println("Active: " + parser.getBoolean(parsed, "active"));
        System.out.println("Missing: " + parser.getString(parsed, "email"));
    }
}

import java.util.*;

public class ValidationResult {
    private List<String> errors = new ArrayList<>();

    public void addError(String field, String message) {
        errors.add(field + ": " + message);
    }

    public boolean isValid() { return errors.isEmpty(); }
    public List<String> getErrors() { return errors; }
}

public class CreateUserRequest {
